// Job board search pages - scraped once daily.
// scraper='jina'    -> Jina AI (free, handles Cloudflare-protected sites)
// scraper='crawl4ai' -> self-hosted Crawl4AI on VPS (free, no limits)
//
// Cloudflare-blocked sites confirmed: indeed.de, devjobs.de
// XING requires Jina (JS-heavy + Cloudflare)

const TARGETS = [
  { url: 'https://berlinstartupjobs.com/engineering/', label: 'berlinstartupjobs-engineering', scraper: 'crawl4ai' },
  { url: 'https://www.remotely.de/jobs/ai-automation', label: 'remotely-ai-automation', scraper: 'crawl4ai' },
  { url: 'https://en.devjobs.de/jobs?q=automation+engineer+remote', label: 'devjobs-automation', scraper: 'jina' },
  { url: 'https://weworkremotely.com/remote-jobs/search?term=automation+engineer', label: 'wwr-automation', scraper: 'crawl4ai' },
  { url: 'https://www.xing.com/jobs/search?keywords=automation+engineer+n8n+KI&location=Deutschland&sort=date', label: 'xing-automation', scraper: 'jina' },

  // --- Stepstone (JS-heavy, Cloudflare → jina) ---
  { url: 'https://www.stepstone.de/jobs/python?homeOffice=2', label: 'stepstone-python', scraper: 'jina' },
  { url: 'https://www.stepstone.de/jobs/automatisierung?homeOffice=2', label: 'stepstone-automation', scraper: 'jina' },
  { url: 'https://www.stepstone.de/jobs/ki-entwickler?homeOffice=2', label: 'stepstone-ki', scraper: 'jina' },

  // --- Indeed (Cloudflare-blocked confirmed → jina) ---
  { url: 'https://de.indeed.com/jobs?q=python+automatisierung&l=remote&fromage=7', label: 'indeed-python', scraper: 'jina' },
  { url: 'https://de.indeed.com/jobs?q=n8n+ki+automatisierung&fromage=7', label: 'indeed-n8n-ki', scraper: 'jina' },

  // --- Monster (Cloudflare → jina) ---
  { url: 'https://www.monster.de/jobs/suche/?q=python-automatisierung&where=remote', label: 'monster-python', scraper: 'jina' },

  // --- Arbeitsagentur Jobbörse (gov, no Cloudflare → crawl4ai) ---
  { url: 'https://www.arbeitsagentur.de/jobsuche/suche?angebotsart=1&was=Python+Automatisierung&wo=Deutschland', label: 'jobboerse-python', scraper: 'crawl4ai' },
  { url: 'https://www.arbeitsagentur.de/jobsuche/suche?angebotsart=1&was=KI+Entwickler&wo=Deutschland', label: 'jobboerse-ki', scraper: 'crawl4ai' },

  // --- Heise Jobs (tech-specific, no heavy protection → crawl4ai) ---
  { url: 'https://jobs.heise.de/?q=python+automation&remote=true', label: 'heise-python', scraper: 'crawl4ai' },

  // --- Praktikum / Werkstudent (remote) ---
  { url: 'https://www.stepstone.de/jobs/praktikum-python?homeOffice=2', label: 'stepstone-praktikum-python', scraper: 'jina' },
  { url: 'https://www.stepstone.de/jobs/werkstudent-python?homeOffice=2', label: 'stepstone-werkstudent', scraper: 'jina' },
  { url: 'https://de.indeed.com/jobs?q=python+KI+praktikum&jt=internship&fromage=14', label: 'indeed-praktikum', scraper: 'jina' },
  { url: 'https://www.arbeitsagentur.de/jobsuche/suche?angebotsart=34&was=Python+Automatisierung&wo=Deutschland', label: 'jobboerse-praktikum', scraper: 'crawl4ai' },
];

return TARGETS.map(t => ({ json: t }));

// Wrap Crawl4AI response into Firecrawl-compatible format.
// Handles both success and continueOnFail error objects gracefully.

const raw = $input.item.json;
const target = $('Scrape Targets').item.json;

// continueOnFail error: raw has { error, statusCode } - treat as failed scrape
if (raw.error || raw.statusCode >= 400) {
  return [{ json: { success: false, data: { markdown: '', metadata: { sourceURL: target.url, scraper: 'crawl4ai', error: raw.error || raw.statusCode } } } }];
}

const markdown = (typeof raw.markdown === 'string' && raw.markdown.length > 50)
  ? raw.markdown
  : '';

return [{
  json: {
    success: markdown.length > 0,
    data: {
      markdown: markdown,
      metadata: {
        sourceURL: raw.url || target.url,
        title: target.label || 'Crawl4AI',
        scraper: 'crawl4ai'
      }
    }
  }
}];

// Wrap Jina AI plain-text response into Firecrawl-compatible format
// so the downstream pipeline (IF: scrape success -> Split -> Normalize) works unchanged.

const raw = $input.item.json;
const target = $('Scrape Targets').item.json;

// n8n HTTP node with responseFormat:text puts body in raw.data
const jinaMarkdown = (typeof raw.data === 'string' && raw.data.length > 0)
  ? raw.data
  : (typeof raw === 'string' ? raw : JSON.stringify(raw));

return [{
  json: {
    success: true,
    data: {
      markdown: jinaMarkdown,
      metadata: {
        sourceURL: target.url,
        title: 'XING Search - Jina AI',
        scraper: 'jina'
      }
    }
  }
}];

// ============================================================
// Split: XING / Listing Page Parser (v2 - URL-based)
//
// Finds all job hyperlinks in the Firecrawl/Jina markdown by URL
// pattern - does NOT depend on numbered list format.
// Each unique xing.com/jobs/ URL becomes a separate item.
// ============================================================

const LISTING_LABELS = ['xing-automation'];

const scrape = $input.item.json;
const target = $('Scrape Targets').item.json;
const label = target.label || '';

if (!LISTING_LABELS.includes(label)) {
  return [{ json: scrape }];
}

const markdown = (scrape.data && scrape.data.markdown) || scrape.markdown || '';
const searchPageUrl = target.url;
const lines = markdown.split('\n');

// Find all [text](url) links in the markdown
const linkPattern = /\[([^\]\n]+)\]\((https?:\/\/[^\)\s\n]{10,})\)/g;
const seen = new Set();
const jobLinks = [];
let m;

while ((m = linkPattern.exec(markdown)) !== null) {
  const linkText = m[1].trim();
  const url = m[2].trim();
  if (seen.has(url)) continue;
  if (url === searchPageUrl) continue;
  // Only XING job detail pages (not search, not image/nav links)
  const isXingJob = url.includes('xing.com/jobs/') && !url.includes('/search') && !url.includes('?keywords');
  if (!isXingJob) continue;
  seen.add(url);
  jobLinks.push({ linkText, url, pos: m.index });
}

if (jobLinks.length === 0) {
  // DEBUG: analyze what's actually in the markdown
  const rawUrlPat = /https?:\/\/[^\s\n"'<>]{10,}/g;
  const xingUrls = [];
  let ru;
  while ((ru = rawUrlPat.exec(markdown)) !== null) {
    if (ru[0].includes('xing')) xingUrls.push(ru[0].substring(0, 80));
  }
  const allLinkPat = /\[([^\]\n]+)\]\((https?:\/\/[^\)\s\n]{5,})\)/g;
  const allLinks = [];
  let al;
  while ((al = allLinkPat.exec(markdown)) !== null) { allLinks.push(al[2].substring(0, 80)); }

  return [{ json: Object.assign({}, scrape, {
    _debug: {
      label: label,
      scraper: (scrape.data && scrape.data.metadata && scrape.data.metadata.scraper) || 'firecrawl',
      markdown_length: markdown.length,
      xing_raw_urls_found: xingUrls,
      all_md_links_count: allLinks.length,
      all_md_links_sample: allLinks.slice(0, 8),
      markdown_first_600: markdown.substring(0, 600)
    }
  }) }];
}

// For each job link, extract surrounding lines as context
const items = [];
for (let i = 0; i < jobLinks.length; i++) {
  const { linkText, url, pos } = jobLinks[i];

  const lineNum = (markdown.substring(0, pos).match(/\n/g) || []).length;
  const ctxStart = Math.max(0, lineNum - 1);
  const ctxEnd   = Math.min(lines.length, lineNum + 20);
  const ctx = lines.slice(ctxStart, ctxEnd)
    .map(l => l.trim())
    .filter(l => l && !l.startsWith('![') && l !== 'Save job' && l !== 'Urgently hiring');

  const h2Line = ctx.find(l => /^#{1,3}\s/.test(l));
  const title = h2Line ? h2Line.replace(/^#{1,3}\s+/, '').trim() : linkText;

  let company = null;
  const h2Idx = h2Line ? ctx.indexOf(h2Line) : -1;
  if (h2Idx >= 0) {
    const after = ctx.slice(h2Idx + 1).filter(l => !/^#{1,3}\s/.test(l) && !l.startsWith('External job'));
    company = after[0] || null;
  }

  const salaryLine = ctx.find(l => l.includes('\u20ac'));
  const salary = salaryLine ? salaryLine.replace(/\s*\*+.*$/, '').trim() : null;

  const dateLine = ctx.find(l => /\d+\s+(hour|day|week|month)s?\s+ago/i.test(l));
  const postedAgo = dateLine ? (dateLine.match(/(\d+\s+(?:hour|day|week|month)s?\s+ago)/i) || [])[1] : null;

  const snip = ['# ' + title];
  if (company)   snip.push('Company: ' + company);
  if (salary)    snip.push('Salary/Type: ' + salary);
  if (postedAgo) snip.push('Posted: ' + postedAgo);
  snip.push('Source: XING');
  snip.push('URL: ' + url);

  items.push({
    json: {
      success: true,
      data: {
        markdown: snip.join('\n'),
        metadata: {
          sourceURL: url,
          title: title + (company ? ' \u2014 ' + company : '')
        }
      }
    }
  });
}

return items;

// UTF-8 sanitizer: replace malformed chars before processing
function sanitizeText(s) {
  if (!s) return s;
  return String(s)
    .replace(/\uFFFD/g, '')   // replacement char
    .replace(/\u0000/g, '')   // null bytes
    .trim();
}

const scrape = $input.item.json;
const target = $('Scrape Targets').item.json;

const markdown = (scrape.data && scrape.data.markdown) || scrape.markdown || '';
const sourceUrl = (scrape.data && scrape.data.metadata && scrape.data.metadata.sourceURL)
               || (scrape.metadata && scrape.metadata.sourceURL)
               || target.url || null;
const pageTitle = (scrape.data && scrape.data.metadata && scrape.data.metadata.title)
               || (scrape.metadata && scrape.metadata.title) || null;

const rawText = markdown.substring(0, 10000);

return [{
  json: {
    normalized_input: {
      input_source: 'scraped',
      source_detail: 'scraped_json',
      email_account_id: null,
      email_address: null,
      email_provider: null,
      subject: pageTitle,
      date: null,
      raw_text: rawText,
      raw_meta: {
        url: sourceUrl,
        label: target.label || null
      }
    }
  }
}];

const ni = $('Normalize Item').item.json.normalized_input;

return [{ json: {
  normalized_input: ni,
  hard_injection_detected: 'no'
} }];

const body = $input.item.json;
let jobEvent;
try {
  let raw = (body.choices[0].message.content || '').trim();
  raw = raw.replace(/<think>[\s\S]*?<\/think>/gi, '').trim();
  raw = raw.replace(/^```(?:json)?\s*/i, '').replace(/\s*```$/, '').trim();
  // If LLM returned an array (multiple jobs from listing page), take first element
  if (raw.startsWith('[')) {
    const arr = JSON.parse(raw);
    jobEvent = Array.isArray(arr) && arr.length > 0 ? arr[0] : { is_job_related: false, action: 'ignore' };
  } else {
    jobEvent = JSON.parse(raw);
  }
} catch (err) {
  // LLM returned non-JSON (e.g. listing page confusion) - silently ignore
  return [{ json: { job_event: {
    is_job_related: false,
    is_job_related_str: 'no',
    action: 'ignore',
    category: 'other',
    injection_suspected: false,
    tech_stack: [],
    key_requirements: [],
    _parse_error: String(err.message).substring(0, 200)
  } } }];
}

if (typeof jobEvent.is_job_related !== 'boolean') jobEvent.is_job_related = false;
if (typeof jobEvent.injection_suspected !== 'boolean') jobEvent.injection_suspected = false;

const ALLOWED_ACTIONS = ['create_job','update_stage','add_interview','add_deadline','log_only','flag_error','ignore'];
if (!ALLOWED_ACTIONS.includes(jobEvent.action)) jobEvent.action = 'ignore';

if (jobEvent.company_id && !/^[a-z0-9][a-z0-9-]*[a-z0-9]$/.test(jobEvent.company_id)) {
  jobEvent.company_id = jobEvent.company_id.toLowerCase().replace(/[^a-z0-9-]/g, '-').replace(/--+/g, '-').replace(/^-|-$/g, '');
}

if (!Array.isArray(jobEvent.tech_stack)) jobEvent.tech_stack = [];
if (!Array.isArray(jobEvent.key_requirements)) jobEvent.key_requirements = [];

const JOB_RELATED_CATEGORIES = ['job_posting','hr_invite','interview_invite','test_task','offer','rejection','follow_up','platform_notification','manual_note'];
if (JOB_RELATED_CATEGORIES.includes(jobEvent.category)) jobEvent.is_job_related = true;

jobEvent.is_job_related_str = jobEvent.is_job_related ? 'yes' : 'no';

return [{ json: { job_event: jobEvent } }];

/* ============================================================
   Prepare DB Params -- Firecrawl Flow
   input_source: scraped, no email_account_id / raw_reference
   ============================================================ */

const e = $input.item.json.job_event;
const ni = $('Normalize Item').item.json.normalized_input;
const rawText = ni.raw_text;
const sourceUrl = (ni.raw_meta && ni.raw_meta.url) || null;

function sql(v) {
  if (v === null || v === undefined) return 'NULL';
  return "'" + String(v).replace(/'/g, "''") + "'";
}
function num(v) {
  if (v === null || v === undefined) return 'NULL';
  const n = parseFloat(v); return isNaN(n) ? 'NULL' : String(n);
}
function bool(v) { return v === true ? 'TRUE' : 'FALSE'; }
function dt(v)   { return v ? "'" + String(v).replace(/'/g, "''") + "'" : 'NULL'; }
function en(v, t) { return v ? "'" + String(v).replace(/'/g, "''") + "'::" + t : 'NULL'; }
function arr(vals) {
  if (!vals || vals.length === 0) return "'{}'";
  const parts = vals.map(v => '"' + String(v).replace(/\\/g, '\\\\').replace(/"/g, '\\"') + '"');
  return "'" + '{' + parts.join(',') + '}' + "'";
}
function jsonb(v) {
  if (!v) return "'{}'::jsonb";
  return "'" + JSON.stringify(v).replace(/'/g, "''") + "'::jsonb";
}

function normWorkMode(v) {
  if (!v) return null;
  const s = String(v).toLowerCase().replace(/[-\s]/g, '_');
  const map = {
    on_site: 'onsite', onsite: 'onsite', in_office: 'onsite', office: 'onsite', vor_ort: 'onsite',
    full_remote: 'remote', fully_remote: 'remote', remote: 'remote', homeoffice: 'remote', home_office: 'remote',
    hybrid: 'hybrid', partially_remote: 'hybrid', teilweise_remote: 'hybrid'
  };
  return map[s] || null;
}
function normSeniority(v) {
  if (!v) return null;
  const s = String(v).toLowerCase().replace(/[-\s]/g, '_');
  const map = {
    intern: 'intern', internship: 'intern', praktikum: 'intern',
    junior: 'junior', jr: 'junior',
    middle: 'middle', mid: 'middle', medior: 'middle', intermediate: 'middle',
    senior: 'senior', sr: 'senior',
    lead: 'lead', tech_lead: 'lead', team_lead: 'lead',
    principal: 'principal', staff: 'principal', architect: 'principal'
  };
  return map[s] || null;
}


const finalSourceUrl = sourceUrl || e.source_url || null;

return [{
  json: {
    job_event: e,
    db: {
      company_id_sql:           sql(e.company_id           || 'unknown'),
      company_name_sql:         sql(e.company_name         || 'Unknown Company'),
      employer_id_sql:          sql(e.employer_id),
      employer_name_sql:        sql(e.employer_name),
      job_id_fuzzy_sql:         sql(e.job_id_fuzzy         || 'unknown__unknown__unknown'),
      job_title_sql:            sql(e.job_title),
      location_sql:             sql(e.location),
      job_thread_key_sql:       sql(e.job_thread_key),
      seniority_sql:            en(normSeniority(e.seniority),             'seniority_enum'),
      work_mode_sql:            en(normWorkMode(e.work_mode),             'work_mode_enum'),
      work_mode_raw_sql:        sql(e.work_mode_raw),
      working_hours_sql:        sql(e.working_hours),
      salary_currency_sql:      sql(e.salary_currency),
      salary_min_sql:           num(e.salary_min),
      salary_max_sql:           num(e.salary_max),
      salary_period_sql:        en(e.salary_period,         'salary_period_enum'),
      tech_stack_sql:           arr(e.tech_stack),
      key_requirements_sql:     arr(e.key_requirements),
      current_stage_sql:        en(e.stage || 'discovered', 'job_stage_enum'),
      priority_sql:             (()=>{const vp=['high','medium','low'];const s=e.priority?String(e.priority).toLowerCase().trim():null;return s&&vp.includes(s)?en(s,'priority_enum'):'NULL';})(),
      priority_level_sql:       num(e.priority_level),
      interview_date_sql:       dt(e.interview_date),
      response_deadline_sql:    dt(e.response_deadline),
      application_deadline_sql: dt(e.application_deadline),
      has_had_call_sql:         bool(e.has_had_call),
      call_count_sql:           String(e.call_count || 0),
      last_call_date_sql:       dt(e.last_call_date),
      source_url_sql:           sql(finalSourceUrl),
      source_input_sql:         en('scraped',               'input_source_enum'),
      summary_sql:              sql(e.summary),
      category_sql:             en(e.category,              'job_category_enum'),
      action_sql:               sql(e.action),
      is_job_related_sql:       bool(e.is_job_related),
      call_platform_sql:        en(e.call_platform,         'call_platform_enum'),
      call_platform_raw_sql:    sql(e.call_platform_raw),
      raw_text_sql:             sql(rawText),
      parsed_json_sql:          jsonb(e),
      sender_risk_level_sql:    sql('unknown'),
      sender_risk_signals_sql:  arr([])
    }
  }
}];

// Filter: Skip Expired
// Drops jobs whose deadline has already passed.
// No deadline ? always pass through (we can't know ? benefit of the doubt).
const e = $('Parse LLM Response').item.json.job_event;
const deadline = e.application_deadline || e.response_deadline || null;

if (deadline) {
  const deadlineDate = new Date(deadline);
  // Guard: invalid date string ? pass through
  if (!isNaN(deadlineDate.getTime()) && deadlineDate < new Date()) {
    // Expired - drop silently
    return [];
  }
}

return [$input.item];
